SELECT students.student_name, badges.badge_name
FROM badges
INNER JOIN students ON badges.student_id = students.student_id;

SELECT DISTINCT student_id
FROM certificates
WHERE course_id = 1;

SELECT COUNT(DISTINCT student_id) 
FROM certificates 
WHERE description = 'Certificate for completing the Digital Marketing course';

SELECT DISTINCT students.student_name
FROM students
JOIN certificates ON students.student_id = certificates.student_id;
